import sys
from collections import defaultdict
class Solution:
    def heapify_insert(self, arr: list[int], n: int, index: int) -> None:
        largest = index
        left = 2 * index + 1
        if left < n and arr[index] < arr[left]:
            largest = left
        right = 2 * index + 2
        if right < n and arr[largest] < arr[right]:
            largest = right
        if largest != index:
            arr[index], arr[largest] = arr[largest], arr[index]
            self.heapify_insert(arr, n, largest)
    def solve(self, nums: list[int]) -> None:
        n = len(nums)
        for i in range(n):
            self.heapify_insert(nums, n, i)            
        for i in range(n - 1, -1, -1):
            print(nums[i], end=' ')

if __name__ == '__main__':
    input = sys.stdin.readline
    n = int(input())
    nums = list(map(int, input().split()))
    solution = Solution()
    solution.solve(nums)
    print('')

