#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
    void heapifyInsert(int arr[], int n, int index) {
        int largest = index;
        int left = 2 * index + 1;
        if (left < n && arr[index] < arr[left]) {
            largest = left;
        }
        int right = 2 * index + 2;
        if (right < n && arr[largest] < arr[right]) {
            largest = right;
        }
        if (largest != index) {
            int temp = arr[index];
            arr[index] = arr[largest];
            arr[largest] = temp;
            heapifyInsert(arr, n, largest);
        }
    }
    void solve(vector<int>& nums) {
        int n = nums.size();
        for (int i = 0; i < n; ++i) {
            heapifyInsert(&nums[0], n, i);
        }
        for (int i = n - 1; i >= 0; --i) {
            cout << nums[i] << ' ';            
        }
    }
};
int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);
    cout.tie(0);
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; ++i) {
        cin >> nums[i];
    }
    Solution().solve(nums);
    return 0;
}
